import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // No fixed-size buffer, use String directly
        String processedInput = userInput.substring(0, Math.min(userInput.length(), 10)); // Limit input size to 10 characters

        System.out.println("Processed input: " + processedInput);
    }
}

### Explanation:
취약유형: Buffer Overflow
